examples.code:
// Basic 3-item dock
<Dock
  items={[
    { key: 'home', icon: HomeIcon, label: 'Home' },
    { key: 'search', icon: SearchIcon, label: 'Search' },
    { key: 'profile', icon: ProfileIcon, label: 'Profile' },
  ]}
  activeKey={activeTab}
  onChange={setActiveTab}
  style={{ position: 'absolute', bottom: spacing.xl, alignSelf: 'center' }}
/>

// Dock with a disabled item
<Dock
  items={[
    { key: 'home', icon: HomeIcon, label: 'Home' },
    { key: 'premium', icon: LockIcon, label: 'Pro', disabled: true },
    { key: 'settings', icon: SettingsIcon, label: 'Settings' },
  ]}
  activeKey={activeTab}
  onChange={setActiveTab}
  style={{ position: 'absolute', bottom: spacing.xl, alignSelf: 'center' }}
/>
